export default function ClientPickerShell() {
  const [clients, setClients] = React.useState([]);
  const [clientId, setClientId] = React.useState("");
  const [client, setClient] = React.useState(null);
  const [docs, setDocs] = React.useState([]);
  const [messages, setMessages] = React.useState([]);
  const [loading, setLoading] = React.useState(false);
  const [msgBody, setMsgBody] = React.useState("");
  const [sendPhase, setSendPhase] = React.useState("idle");
  const [activeTab, setActiveTab] = React.useState("docs");

  React.useEffect(() => {
    tools.host_listClients({}).then((r) => {
      setClients(r.data || []);
      if (r.data && r.data.length > 0) {
        setClientId(r.data[0].id);
      }
    });
  }, []);

  React.useEffect(() => {
    if (!clientId) return;
    setLoading(true);
    Promise.all([
      tools.host_getClient({ id: clientId }),
      tools.host_listClientDocuments({ id: clientId }),
      tools.host_listClientMessages({ id: clientId }),
    ]).then(([c, d, m]) => {
      setClient(c);
      setDocs(d.data || []);
      setMessages(m.data || []);
      setLoading(false);
    });
  }, [clientId]);

  const sendMessage = async () => {
    if (!msgBody.trim()) return;
    setSendPhase("sending");
    const result = await tools.host_sendClientMessage({
      id: clientId,
      body: { body: msgBody, author: "firm" },
    });
    setSendPhase(result && result.status === "pending-approval" ? "awaiting" : "sent");
    if (result && result.status !== "pending-approval") {
      setMsgBody("");
      setSendPhase("idle");
      tools.host_listClientMessages({ id: clientId }).then((m) => setMessages(m.data || []));
    }
  };

  const statusMeta = (s) => {
    const map = {
      missing: { label: "Missing", color: "#B0473A", bg: "#fdf2f1" },
      received: { label: "Received", color: "#7c6f3e", bg: "#fdf8ec" },
      needs_review: { label: "Needs review", color: "#7c6f3e", bg: "#fdf8ec" },
      verified: { label: "Verified", color: "#2d6a4f", bg: "#edf7f2" },
      rejected: { label: "Rejected", color: "#B0473A", bg: "#fdf2f1" },
    };
    return map[s] || { label: s, color: "#46443f", bg: "#f3f2ef" };
  };

  const progressReceived = docs.filter((d) => d.status === "verified" || d.status === "received").length;
  const progressVerified = docs.filter((d) => d.status === "verified").length;
  const total = docs.length;

  const containerStyle = {
    fontFamily: "var(--vendo-font-family)",
    color: "var(--vendo-color-text)",
    background: "var(--vendo-color-background)",
    minHeight: "100vh",
    padding: "0 0 40px 0",
  };

  const surfaceStyle = {
    background: "var(--vendo-color-surface)",
    border: "1px solid var(--vendo-color-border)",
    borderRadius: "var(--vendo-radius-medium)",
    padding: "20px 24px",
  };

  const labelStyle = {
    fontSize: "11px",
    fontWeight: 600,
    letterSpacing: "0.06em",
    textTransform: "uppercase",
    color: "var(--vendo-color-muted)",
    marginBottom: 4,
  };

  const pill = (s) => {
    const m = statusMeta(s);
    return (
      <span style={{
        display: "inline-block",
        fontSize: "12px",
        fontWeight: 600,
        padding: "2px 10px",
        borderRadius: "999px",
        background: m.bg,
        color: m.color,
        border: `1px solid ${m.color}22`,
      }}>{m.label}</span>
    );
  };

  if (!clientId && clients.length === 0) {
    return (
      <div style={containerStyle}>
        <div style={{ ...surfaceStyle, color: "var(--vendo-color-muted)", fontSize: 14 }}>
          No clients found.
        </div>
      </div>
    );
  }

  return (
    <div style={containerStyle}>
      {/* Client selector */}
      <div style={{ marginBottom: 20 }}>
        <div style={labelStyle}>Client</div>
        <select
          value={clientId}
          onChange={(e) => setClientId(e.target.value)}
          style={{
            fontFamily: "var(--vendo-font-family)",
            fontSize: "15px",
            padding: "8px 12px",
            borderRadius: "var(--vendo-radius-small)",
            border: "1px solid var(--vendo-color-border)",
            background: "var(--vendo-color-surface)",
            color: "var(--vendo-color-text)",
            minWidth: 260,
            cursor: "pointer",
          }}
        >
          {clients.map((c) => (
            <option key={c.id} value={c.id}>{c.name}</option>
          ))}
        </select>
      </div>

      {loading && (
        <div style={{ color: "var(--vendo-color-muted)", fontSize: 14, padding: "24px 0" }}>Loading…</div>
      )}

      {!loading && client && (
        <div style={{ display: "grid", gap: 16 }}>
          {/* Hero: client identity + assignment */}
          <div style={{ ...surfaceStyle, display: "grid", gap: 12 }}>
            <div style={{ display: "flex", alignItems: "flex-start", justifyContent: "space-between", flexWrap: "wrap", gap: 12 }}>
              <div>
                <div style={{ fontSize: "22px", fontWeight: 700, lineHeight: 1.2 }}>{client.name}</div>
                <div style={{ fontSize: "13px", color: "var(--vendo-color-muted)", marginTop: 3 }}>
                  {client.entityType || client.entity_type || ""}
                  {(client.entityType || client.entity_type) && client.email ? " · " : ""}
                  {client.email || ""}
                </div>
              </div>
              <div style={{ display: "flex", gap: 8, alignItems: "center", flexWrap: "wrap" }}>
                {client.status && pill(client.status)}
                {client.filingDeadline || client.filing_deadline ? (
                  <span style={{
                    fontSize: "12px",
                    fontWeight: 500,
                    color: "var(--vendo-color-muted)",
                    background: "var(--vendo-color-background)",
                    border: "1px solid var(--vendo-color-border)",
                    borderRadius: "var(--vendo-radius-small)",
                    padding: "3px 10px",
                  }}>
                    Filing deadline: {new Date(client.filingDeadline || client.filing_deadline).toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" })}
                  </span>
                ) : null}
              </div>
            </div>

            {/* Staff + progress row */}
            <div style={{ display: "flex", gap: 24, flexWrap: "wrap", paddingTop: 8, borderTop: "1px solid var(--vendo-color-border)" }}>
              <div>
                <div style={labelStyle}>Assigned staff</div>
                <div style={{ fontSize: "14px", fontWeight: 500 }}>
                  {client.assignedStaff || client.assigned_staff || client.staff || "—"}
                </div>
              </div>
              <div>
                <div style={labelStyle}>Documents verified</div>
                <div style={{ fontSize: "14px", fontWeight: 600 }}>
                  {progressVerified} of {total}
                  {total > 0 ? (
                    <span style={{ fontWeight: 400, color: "var(--vendo-color-muted)", marginLeft: 6 }}>
                      ({Math.round((progressVerified / total) * 100)}%)
                    </span>
                  ) : null}
                </div>
              </div>
              <div>
                <div style={labelStyle}>Received (incl. pending review)</div>
                <div style={{ fontSize: "14px", fontWeight: 600 }}>
                  {progressReceived} of {total}
                </div>
              </div>
              {total > 0 && (
                <div style={{ flex: 1, minWidth: 160, display: "flex", flexDirection: "column", justifyContent: "flex-end" }}>
                  <div style={{ height: 6, background: "var(--vendo-color-border)", borderRadius: 99, overflow: "hidden" }}>
                    <div style={{
                      height: "100%",
                      width: `${Math.round((progressVerified / total) * 100)}%`,
                      background: "var(--vendo-color-accent)",
                      borderRadius: 99,
                      transition: "width 0.4s",
                    }}/>
                  </div>
                </div>
              )}
            </div>
          </div>

          {/* Tabs */}
          <div style={{ display: "flex", gap: 0, borderBottom: "1px solid var(--vendo-color-border)" }}>
            {[{ key: "docs", label: "Document checklist" }, { key: "messages", label: "Messages" }].map((t) => (
              <button
                key={t.key}
                onClick={() => setActiveTab(t.key)}
                style={{
                  fontFamily: "var(--vendo-font-family)",
                  fontSize: "14px",
                  fontWeight: activeTab === t.key ? 600 : 400,
                  padding: "10px 20px",
                  border: "none",
                  borderBottom: activeTab === t.key ? "2px solid var(--vendo-color-accent)" : "2px solid transparent",
                  background: "transparent",
                  color: activeTab === t.key ? "var(--vendo-color-text)" : "var(--vendo-color-muted)",
                  cursor: "pointer",
                  marginBottom: -1,
                }}
              >{t.label}</button>
            ))}
          </div>

          {/* Document checklist */}
          {activeTab === "docs" && (
            <div style={surfaceStyle}>
              {docs.length === 0 ? (
                <div style={{ color: "var(--vendo-color-muted)", fontSize: 14 }}>No documents on this client's checklist.</div>
              ) : (
                <table style={{ width: "100%", borderCollapse: "collapse", fontSize: "14px" }}>
                  <thead>
                    <tr style={{ borderBottom: "1px solid var(--vendo-color-border)" }}>
                      {["Document", "Status", "File", "Note"].map((h) => (
                        <th key={h} style={{ textAlign: "left", padding: "6px 10px 10px", fontWeight: 600, fontSize: "11px", letterSpacing: "0.05em", textTransform: "uppercase", color: "var(--vendo-color-muted)" }}>{h}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {docs.map((doc, i) => (
                      <tr key={doc.id || i} style={{ borderBottom: "1px solid var(--vendo-color-border)" }}>
                        <td style={{ padding: "11px 10px", fontWeight: 500 }}>{doc.name || doc.label || doc.type || "—"}</td>
                        <td style={{ padding: "11px 10px" }}>{pill(doc.status)}</td>
                        <td style={{ padding: "11px 10px", color: "var(--vendo-color-muted)", fontSize: 13 }}>
                          {doc.fileName || doc.file_name || doc.uploadedFile || "—"}
                        </td>
                        <td style={{ padding: "11px 10px", color: doc.rejectionNote || doc.rejection_note ? "#B0473A" : "var(--vendo-color-muted)", fontSize: 13 }}>
                          {doc.rejectionNote || doc.rejection_note || "—"}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              )}
            </div>
          )}

          {/* Messages */}
          {activeTab === "messages" && (
            <div style={{ display: "grid", gap: 12 }}>
              <div style={{ ...surfaceStyle, display: "grid", gap: 10, maxHeight: 420, overflowY: "auto" }}>
                {messages.length === 0 ? (
                  <div style={{ color: "var(--vendo-color-muted)", fontSize: 14 }}>No messages yet. Send one below to start the conversation.</div>
                ) : (
                  messages.map((msg, i) => {
                    const isFirm = msg.author === "firm" || msg.from === "firm" || msg.sender === "firm";
                    return (
                      <div key={msg.id || i} style={{
                        display: "flex",
                        flexDirection: "column",
                        alignItems: isFirm ? "flex-end" : "flex-start",
                      }}>
                        <div style={{
                          maxWidth: "72%",
                          background: isFirm ? "var(--vendo-color-accent)" : "var(--vendo-color-background)",
                          color: isFirm ? "var(--vendo-color-accent-text, #fff)" : "var(--vendo-color-text)",
                          border: isFirm ? "none" : "1px solid var(--vendo-color-border)",
                          borderRadius: "var(--vendo-radius-medium)",
                          padding: "10px 14px",
                          fontSize: "14px",
                          lineHeight: 1.5,
                        }}>
                          {msg.body || msg.text || msg.content || ""}
                        </div>
                        <div style={{ fontSize: "11px", color: "var(--vendo-color-muted)", marginTop: 3, padding: "0 4px" }}>
                          {isFirm ? "Firm" : "Client"}
                          {msg.createdAt || msg.created_at || msg.sentAt ? (
                            <> · {new Date(msg.createdAt || msg.created_at || msg.sentAt).toLocaleString("en-US", { month: "short", day: "numeric", hour: "numeric", minute: "2-digit" })}</>
                          ) : null}
                        </div>
                      </div>
                    );
                  })
                )}
              </div>

              {/* Compose */}
              <div style={surfaceStyle}>
                <div style={labelStyle}>Send a message to client</div>
                <textarea
                  value={msgBody}
                  onChange={(e) => setMsgBody(e.target.value)}
                  placeholder="Type your message…"
                  rows={3}
                  style={{
                    width: "100%",
                    fontFamily: "var(--vendo-font-family)",
                    fontSize: "14px",
                    padding: "10px 12px",
                    border: "1px solid var(--vendo-color-border)",
                    borderRadius: "var(--vendo-radius-small)",
                    background: "var(--vendo-color-background)",
                    color: "var(--vendo-color-text)",
                    resize: "vertical",
                    boxSizing: "border-box",
                    marginBottom: 10,
                  }}
                />
                <button
                  onClick={sendMessage}
                  disabled={!msgBody.trim() || sendPhase === "sending" || sendPhase === "awaiting"}
                  style={{
                    fontFamily: "var(--vendo-font-family)",
                    fontSize: "14px",
                    fontWeight: 600,
                    padding: "9px 20px",
                    borderRadius: "var(--vendo-radius-small)",
                    border: "none",
                    background: (!msgBody.trim() || sendPhase !== "idle") ? "var(--vendo-color-border)" : "var(--vendo-color-accent)",
                    color: (!msgBody.trim() || sendPhase !== "idle") ? "var(--vendo-color-muted)" : "var(--vendo-color-accent-text, #fff)",
                    cursor: (!msgBody.trim() || sendPhase !== "idle") ? "not-allowed" : "pointer",
                  }}
                >
                  {sendPhase === "awaiting" ? "Awaiting approval…" : sendPhase === "sending" ? "Sending…" : "Send message"}
                </button>
                {sendPhase === "awaiting" && (
                  <div style={{ marginTop: 8, fontSize: 13, color: "var(--vendo-color-muted)" }}>
                    This message is pending approval before it reaches the client.
                  </div>
                )}
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
}
